scwin.f_displayCongestion = function (returnVal, vTime) {
  var wating = "";
  var rTime = "";
  rTime = vTime;
  if (returnVal == 0) {
    //혼잡이 아닌경우

    congest1.setValue("<b><font color=blue>CY정상</font>" + wating);
  } else {
    //혼잡인 경우

    if (rTime != undefined) {
      congest2.setValue("&nbsp;&nbsp;<font color=black>예상 대기시간 : " + rTime + "</font></b>");
    }
    if (returnVal == 1) {
      congest1.setValue("<b><font color=red>CY혼잡</font>" + wating);
    } else {
      congest1.setValue("<b><font color=red>CY장비고장</font>" + wating);
    }
  }
  //f_resetScanData();
};

