scwin.f_printOnoffInfo = async function () {
  var row = ds_onOffSituation.getRowPosition();
  var crryinoutIntendNo = ds_onOffSituation.getCellData(row, "crryinoutIntendNo");
  if (ds_onOffSituation.getCellData(row, "forceYn") != "1") {
    if (ds_onOffSituation.getCellData(row, "wrkStsCd") == "F") {
      alert("상하차 완료건은 송장을 출력 할 수 없습니다.");
      return;
    }
    ;
    var cfrm = await $c.win.confirm($p, "자가건이면 [확인], 당사건이면 [취소]를 눌러주세요\n\n자가건을 당사폼으로 출력하려고 하면\n\n정상적으로 출력되지 않을 수 있습니다.");
    if (cfrm) {
      await scwin.f_OzReportForSucess(crryinoutIntendNo, "JE");
    } else {
      await scwin.f_OzReportForSucess(crryinoutIntendNo, "LS");
    }
  } else {
    alert("강제등록건은 송장을 출력 할 수 없습니다.");
  }
};

//-------------------------------------------------------------------------
//문자열을 날자형식으로 맞도록 처리
//val : 넘기는날짜형식문자열
//itv : interval
//-------------------------------------------------------------------------
scwin.f_setDate = function (val, itv) {
  var year = parseInt(val.substr(0, 4), 10);
  var month = parseInt(val.substr(4, 2), 10) - 1;
  var date = parseInt(val.substr(6, 2), 10);
  var d = new Date(year, month, date);
  d.setDate(d.getDate() + itv);
  var yyyy = d.getFullYear();
  var mm = scwin.addZero(d.getMonth() + 1);
  var dd = scwin.addZero(d.getDate());
  return "" + yyyy + mm + dd;
};
scwin.addZero = function (num) {
  return num < 10 ? "0" + num : num;
};
scwin.sbm_retrieve_submitdone = function () {
  if ($c.gus.cfCheckCreateFlag($p) == true) {
    $c.gus.cfTurnCreateFlag($p, false);
  } else {
    if (ds_onOffSituation.getRowCount() == 0) {
      alert("조회된 데이터가 없습니다");
    } else {
      totalRows.setValue(ds_onOffSituation.getRowCount());
    }
    ;
  }
  ;
  for (var row = 0; row <= ds_onOffSituation.getRowCount(); row++) {
    if (ds_onOffSituation.getCellData(row, "wrkStsCd") == "F") {
      gr_onOffSituation.setReadOnly("cell", row, "cntrNo", false);
    } else {
      gr_onOffSituation.setReadOnly("cell", row, "cntrNo", true);
    }
    ;
    if (ds_onOffSituation.getCellData(row, "odrNo") == "F") {
      gr_onOffSituation.setReadOnly("cell", row, "odrNo", false);
    } else {
      gr_onOffSituation.setReadOnly("cell", row, "odrNo", true);
    }
    ;
    if (ds_onOffSituation.getCellData(row, "crryinoutClsCd") == "I") {
      gr_onOffSituation.setCellColor(row, "carryinoutClsNm", "black");
      gr_onOffSituation.setCellColor(row, "wrkMemo", "black");
      if (ds_onOffSituation.getCellData(row, "wrkStsCd") == "F") {
        gr_onOffSituation.setCellColor(row, "cntrNo", "blue");
      } else {
        gr_onOffSituation.setCellColor(row, "cntrNo", "black");
      }
    } else {
      gr_onOffSituation.setCellColor(row, "carryinoutClsNm", "red");
      gr_onOffSituation.setCellColor(row, "cntrNo", "red");
      gr_onOffSituation.setCellColor(row, "wrkMemo", "red");
    }
    ;
    if (ds_onOffSituation.getCellData(row, "wrkStsCd") == "F") {
      gr_onOffSituation.setCellColor(row, "wrkStsCd", "green");

      // gatelogNo 없음
      if (ds_onOffSituation.getCellData(row, "gatelogNo") == null || ds_onOffSituation.getCellData(row, "gatelogNo") == "") {
        // 강제 처리
        if (ds_onOffSituation.getCellData(row, "forceYn") == "1") {
          if (ds_onOffSituation.getCellData(row, "crryinoutClsCd") == "I") {
            ds_onOffSituation.setCellData(row, "cntrStats", "강제하차");
          } else {
            ds_onOffSituation.setCellData(row, "cntrStats", "강제상차");
          }
          gr_onOffSituation.setCellCo;
        } else {
          // 일반 처리
          // lineCd별 처리 (결과는 동일)
          if (ds_onOffSituation.getCellData(row, "crryinoutClsCd") == "I") {
            ds_onOffSituation.setCellData(row, "cntrStats", "미반입");
          } else {
            ds_onOffSituation.setCellData(row, "cntrStats", "미반출");
          }
        }
      } else {
        // gatelogNo 있음

        if (ds_onOffSituation.getCellData(row, "crryinoutClsCd") == "I") {
          ds_onOffSituation.setCellData(row, "cntrStats", "반입완료");
        } else {
          ds_onOffSituation.setCellData(row, "cntrStats", "반출완료");
        }
      }
    } else if (ds_onOffSituation.getCellData(row, "wrkStsCd") == "R") {
      gr_onOffSituation.setCellColor(row, "wrkStsCd", "blue");
    } else {
      gr_onOffSituation.setCellColor(row, "wrkStsCd", "red");
    }
  }
  ;
};
